import ccxt.async_support as ccxt  # noqa: F402
from ccxt.test.exchange.base import test_shared_methods  # noqa E402

def test_is_json_encoded_object():
    exchange = ccxt.Exchange({
        'id': 'sampleexchange',
    })
    assert exchange.is_json_encoded_object('{"key":"value"}')
    assert exchange.is_json_encoded_object('{}')
    assert exchange.is_json_encoded_object('[]')
    # todo: the belows  are not ideal, but currently valid
    assert exchange.is_json_encoded_object('{x')
    assert exchange.is_json_encoded_object('[x')
    assert exchange.is_json_encoded_object('{')
    assert exchange.is_json_encoded_object('[')
    # invalid
    assert not exchange.is_json_encoded_object('x')
    assert not exchange.is_json_encoded_object('')
    assert not exchange.is_json_encoded_object('}')
    assert not exchange.is_json_encoded_object(']')
    assert not exchange.is_json_encoded_object('null')
    assert not exchange.is_json_encoded_object('undefined')
